- **Reasoning:** Use `Mathf.Lerp()` or direct vector interpolation between two Color values based on normalized progress (current hits / requiredHits). Unity's Color struct supports LERP operations directly.
- **Solution:** Implement UpdateUI with color calculation and display the complete updated class:

```csharp
using UnityEngine;
using UnityEngine.UI;

public class AbilityChargeUI : MonoBehaviour {
    public Image chargeIndicator;

    [Range(0, 1)] // Optional range attribute for editor visibility

    private int currentHits = 0;

    // Start is called once before the first execution of Update after the MonoBehaviour is created
    public void Init(int _requiredHits) {
        requiredHits = _requiredHits;
        chargeIndicator.color = minValueColor;
    }

    public void AddHit() {
        currentHits++;
        if (currentHits >= requiredHits) currentHits = requiredHits - 1; // Clamp max value

        UpdateUI();
    }

    public void UpdateUI() {

        float progress = Mathf.Clamp01((float)(requiredHits > 0 ? currentHits : 0f) / (float)requiredHits);
        chargeIndicator.color = Color.Lerp(minValueColor, maxValueColor, progress);

    }

    // Update is called once per frame
    void LateUpdate() {
        if(chargeIndicator != null && requiredHits > 0)
            ChargeRatio();
    }

}
```

- **Justification:** Based on [AbilityChargeUI] documentation - implements color interpolation using `Color.Lerp(minValueColor, maxValueColor, progress)` where progress = current/required hits.
